const prs = $input.all().map(i => i.json);
const workspace = $('Extract Workspaces').first().json;
const repoName = (workspace.github_repos ?? [])[0] ?? '';
const now = Date.now();

const merged = prs.filter(pr => pr.state === 'closed' && pr.merged_at);
const open = prs.filter(pr => pr.state === 'open');
const closedWithoutMerge = prs.filter(pr => pr.state === 'closed' && !pr.merged_at);

const reviewLags = merged
  .filter(pr => pr.merged_at && pr.created_at)
  .map(pr => (new Date(pr.merged_at).getTime() - new Date(pr.created_at).getTime()) / 3600000);

const avgReviewLag = reviewLags.length > 0
  ? reviewLags.reduce((s, v) => s + v, 0) / reviewLags.length
  : 0;

const oldestOpenDays = open.length > 0
  ? Math.max(...open.map(pr => (now - new Date(pr.created_at).getTime()) / 86400000))
  : 0;

const totalClosed = merged.length + closedWithoutMerge.length;
const mergeRate = totalClosed > 0 ? merged.length / totalClosed : 0;

const prList = prs.map(pr => ({
  number: pr.number,
  title: pr.title,
  state: pr.state,
  merged_at: pr.merged_at ? new Date(pr.merged_at).toISOString() : null,
  created_at: new Date(pr.created_at).toISOString(),
  updated_at: new Date(pr.updated_at).toISOString(),
  author: pr.user?.login ?? null,
  labels: (pr.labels ?? []).map(l => l.name),
  url: pr.html_url,
  draft: pr.draft ?? false,
  review_lag_hours: pr.merged_at
    ? Math.round((new Date(pr.merged_at).getTime() - new Date(pr.created_at).getTime()) / 3600000 * 10) / 10
    : null
}));

return [{ json: {
  workspace_id: workspace.id,
  repo_full_name: repoName,
  prs_merged: merged.length,
  prs_open: open.length,
  prs_closed_without_merge: closedWithoutMerge.length,
  avg_review_lag_hours: Math.round(avgReviewLag * 10) / 10,
  oldest_open_pr_days: Math.round(oldestOpenDays * 10) / 10,
  merge_rate: Math.round(mergeRate * 10000) / 10000,
  pr_list: prList,
  synced_at: new Date().toISOString()
}}];

const staticData = $getWorkflowStaticData('global');
const seenPRs = new Set(staticData.seenPRNumbers ?? []);

const prList = $json.pr_list ?? [];
const repoName = $json.repo_full_name;

// If seenPRNumbers was populated when pr_list was broken (empty), reset it
if (seenPRs.size > 0 && prList.length > 0 && [...seenPRs].every(n => typeof n !== 'number' || n === 0)) {
  seenPRs.clear();
}

const newPRs = prList
  .filter(pr => !seenPRs.has(pr.number))
  .map(pr => ({ ...pr, repo_full_name: repoName }));

const allNumbers = [...new Set([...seenPRs, ...prList.map(pr => pr.number)])];
staticData.seenPRNumbers = allNumbers.slice(-1000);

return { new_prs: newPRs };
